const { floodRiskCategory, designWindSpeed, thermalEnvelopeRating, materialDurabilityScore, foundationResilienceScore, roofSystemResilience, siteDrainageEffectiveness, maintenanceAndMonitoring } = inputs;

// Input validation and normalization
const validatedFloodRisk = Math.max(1, Math.min(5, floodRiskCategory));
const validatedWindSpeed = Math.max(70, Math.min(180, designWindSpeed));
const validatedThermalRating = Math.max(1, Math.min(5, thermalEnvelopeRating));
const validatedMaterialScore = Math.max(1, Math.min(5, materialDurabilityScore));
const validatedFoundationScore = Math.max(1, Math.min(5, foundationResilienceScore));
const validatedRoofScore = Math.max(1, Math.min(5, roofSystemResilience));
const validatedDrainage = Math.max(1, Math.min(5, siteDrainageEffectiveness));
const validatedMaintenance = Math.max(1, Math.min(5, maintenanceAndMonitoring));

// Convert 1-5 ratings to 0-1 resilience factors (higher is better)
const floodFactor = (5 - validatedFloodRisk) / 4; // 1 (min risk) -> 1, 5 (max risk) -> 0
const thermalFactor = (validatedThermalRating - 1) / 4;
const materialFactor = (validatedMaterialScore - 1) / 4;
const foundationFactor = (validatedFoundationScore - 1) / 4;
const roofFactor = (validatedRoofScore - 1) / 4;
const drainageFactor = (validatedDrainage - 1) / 4;
const maintenanceFactor = (validatedMaintenance - 1) / 4;

// Convert design wind speed to 0-1 resilience factor (higher is better)
// Assume max design wind speed for highest resilience is 180 MPH
const windFactor = Math.min(validatedWindSpeed / 180, 1); 

// Define weights for each factor (sum to 1.0)
const weights = {
  flood: 0.20,
  wind: 0.20,
  thermal: 0.10,
  material: 0.15,
  foundation: 0.10,
  roof: 0.10,
  drainage: 0.10,
  maintenance: 0.05
};

// Calculate weighted sum
let rawScore = (
  floodFactor * weights.flood +
  windFactor * weights.wind +
  thermalFactor * weights.thermal +
  materialFactor * weights.material +
  foundationFactor * weights.foundation +
  roofFactor * weights.roof +
  drainageFactor * weights.drainage +
  maintenanceFactor * weights.maintenance
) * 100; // Scale to 0-100

// Ensure score is within 0-100 bounds
const resilienceScore = Math.max(0, Math.min(100, rawScore));

// Determine resilience category
let resilienceCategory;
if (resilienceScore < 30) {
  resilienceCategory = "Critical Vulnerability";
} else if (resilienceScore < 50) {
  resilienceCategory = "High Vulnerability";
} else if (resilienceScore < 70) {
  resilienceCategory = "Moderate Resilience";
} else if (resilienceScore < 85) {
  resilienceCategory = "Good Resilience";
} else {
  resilienceCategory = "Exceptional Resilience";
}

return { resilienceScore, resilienceCategory };
